// This file is hand-written (NOT generated by Fern) and holds regression tests
// for the users authentication-methods client. Keep it separate from the
// Fern-generated *_test.go file so it survives SDK regeneration.

package users_authentication_methods_test

import (
	context "context"
	http "net/http"
	httptest "net/http/httptest"
	testing "testing"

	require "github.com/stretchr/testify/require"

	client "github.com/auth0/go-auth0/v2/management/client"
	option "github.com/auth0/go-auth0/v2/management/option"
)

// objectShapedAuthMethodsBody is the response the Auth0 API returns when
// include_totals=true: an object wrapping the authenticators array plus totals.
// This is the only shape the List pager can decode.
const objectShapedAuthMethodsBody = `{
  "start": 0,
  "limit": 50,
  "total": 1,
  "authenticators": [
    {
      "id": "auth-method-id",
      "type": "phone",
      "confirmed": true,
      "name": "name"
    }
  ]
}`

// TestUsersAuthenticationMethodsList_NilRequestSendsIncludeTotals reproduces the
// regression where calling List with a nil request produced:
//
//	json: cannot unmarshal array into Go value of type management.unmarshaler
//
// A nil request must still apply the client's default query parameters (notably
// include_totals=true), which selects the object-shaped response the pager can
// decode. Without the fix in internal.QueryValuesWithDefaults, no include_totals
// param was sent, the API defaulted it to false and returned a bare array, and
// decoding failed.
func TestUsersAuthenticationMethodsList_NilRequestSendsIncludeTotals(t *testing.T) {
	var gotIncludeTotals string

	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		gotIncludeTotals = r.URL.Query().Get("include_totals")

		// Emulate the real API: only return the object shape when
		// include_totals=true; otherwise return the bare array that the pager
		// cannot decode. This makes the test fail loudly if the default is
		// ever dropped again.
		if gotIncludeTotals != "true" {
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte(`[{"id":"auth-method-id","type":"phone"}]`))

			return
		}

		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(objectShapedAuthMethodsBody))
	}))
	defer server.Close()

	c := client.NewWithOptions(
		option.WithBaseURL(server.URL),
		option.WithToken("test-token"),
		option.WithHTTPClient(server.Client()),
	)

	// The crux of the regression: a nil request must not panic or fail to decode.
	page, err := c.Users.AuthenticationMethods.List(
		context.Background(),
		"id",
		nil,
	)
	require.NoError(t, err, "List with a nil request should succeed")
	require.Equal(t, "true", gotIncludeTotals, "include_totals=true must be sent for a nil request")
	require.NotNil(t, page)
	require.Len(t, page.Results, 1)
	require.Equal(t, "auth-method-id", page.Results[0].GetID())
}
